module comparator_16bit (
    input [15:0] obf_A,
    input [15:0] B,
    output reg A_equals_B,
    output reg A_greater_B,
    output reg A_less_B
);
    always @(*) begin
        A_equals_B = (obf_A == B);
        A_greater_B = (obf_A > B);
        A_less_B = (obf_A < B);
    end
endmodule
